SELECT ?amount WHERE {
  ?event wdt:P230 wd:Q61917;
         wdt:P230 wd:Q72353;
         wdt:P585 ?date;
         wdt:P2047 ?duration.
  FILTER (?date > "1972-01-01T00:00:00Z"^^xsd:dateTime)
  ?duration wikibase:quantityValue ?amount.
  ORDER BY ASC(?amount)
  LIMIT 1
  OFFSET 2
}

